import { type StatsOptions } from '@rspack/core';

export function getStatsOptions(verbose = false): StatsOptions {
  const rspackStatsOptions: StatsOptions = {
    all: false, // Fallback value for stats options when an option is not defined. It has precedence over local webpack defaults.
    colors: true,
    hash: true, // required by custom stat output
    timings: true, // required by custom stat output
    chunks: true, // required by custom stat output
    builtAt: true, // required by custom stat output
    warnings: true,
    errors: true,
    assets: true, // required by custom stat output
    cachedAssets: true, // required for bundle size calculators

    // Needed for markAsyncChunksNonInitial.
    ids: true,
    entrypoints: true,
  };

  const verboseStatsOutputOptions: StatsOptions = {
    // The verbose output will most likely be piped to a file, so colors just mess it up.
    colors: false,
    usedExports: true,
    optimizationBailout: true,
    reasons: true,
    children: true,
    assets: true,
    version: true,
    chunkModules: true,
    errorDetails: true,
    errorStack: true,
    moduleTrace: true,
    logging: 'verbose',
    modulesSpace: Infinity,
  };

  return verbose
    ? { ...rspackStatsOptions, ...verboseStatsOutputOptions }
    : rspackStatsOptions;
}

import type { ExecutorContext } from '@nx/devkit';
import {
  createTmpTsConfig,
  DependentBuildableProjectNode,
} from '@nx/js/internal';
import { NgPackagr } from 'ng-packagr';
import { join, resolve } from 'path';
import { createLibraryExecutor } from '../package/package.impl';
import type { BuildAngularLibraryExecutorOptions } from '../package/schema';
import { parseRemappedTsConfigAndMergeDefaults } from '../utilities/typescript';
import { getNgPackagrInstance } from './ng-packagr-adjustments/ng-packagr';

async function initializeNgPackgrLite(
  options: BuildAngularLibraryExecutorOptions,
  context: ExecutorContext,
  projectDependencies: DependentBuildableProjectNode[]
): Promise<NgPackagr> {
  const ngPackagr = await getNgPackagrInstance();
  ngPackagr.forProject(resolve(context.root, options.project));

  if (options.tsConfig) {
    const remappedTsConfigFilePath = createTmpTsConfig(
      join(context.root, options.tsConfig),
      context.root,
      context.projectsConfigurations.projects[context.projectName].root,
      projectDependencies
    );
    const tsConfig = await parseRemappedTsConfigAndMergeDefaults(
      context.root,
      options.tsConfig,
      remappedTsConfigFilePath
    );
    ngPackagr.withTsConfig(tsConfig);
  }

  return ngPackagr;
}

export const ngPackagrLiteExecutor = createLibraryExecutor(
  initializeNgPackgrLite
);

export default ngPackagrLiteExecutor;

import {
  addDependenciesToPackageJson,
  type GeneratorCallback,
  type Tree,
} from '@nx/devkit';
import {
  typescriptESLintVersion as latestTypescriptESLintVersion,
  useFlatConfig,
} from '@nx/eslint/internal';
import { versions } from '../../utils/version-utils';
import { isBuildableLibraryProject } from './buildable-project';

export function addAngularEsLintDependencies(
  tree: Tree,
  projectName: string
): GeneratorCallback {
  const compatVersions = versions(tree);
  const angularEslintVersionToInstall = compatVersions.angularEslintVersion;
  const usesEslintFlatConfig = useFlatConfig(tree);
  const devDependencies = usesEslintFlatConfig
    ? {
        'angular-eslint': angularEslintVersionToInstall,
      }
    : {
        '@angular-eslint/eslint-plugin': angularEslintVersionToInstall,
        '@angular-eslint/eslint-plugin-template': angularEslintVersionToInstall,
        '@angular-eslint/template-parser': angularEslintVersionToInstall,
      };

  if ('typescriptEslintVersion' in compatVersions) {
    devDependencies['@typescript-eslint/utils'] = usesEslintFlatConfig
      ? latestTypescriptESLintVersion
      : compatVersions.typescriptEslintVersion;
  }

  if (isBuildableLibraryProject(tree, projectName)) {
    const jsoncEslintParserVersionToInstall =
      versions(tree).jsoncEslintParserVersion;
    devDependencies['jsonc-eslint-parser'] = jsoncEslintParserVersionToInstall;
  }

  return addDependenciesToPackageJson(
    tree,
    {},
    devDependencies,
    undefined,
    true
  );
}

import type { Tree } from '@nx/devkit';
import {
  formatFiles,
  installPackagesTask,
  readProjectConfiguration,
} from '@nx/devkit';
import { assertSupportedAngularVersion } from '../../utils/assert-supported-angular-version';
import {
  addDependencies,
  addHydration,
  addServerFile,
  generateSSRFiles,
  generateTsConfigServerJsonForBrowserBuilder,
  normalizeOptions,
  setRouterInitialNavigation,
  setServerTsConfigOptionsForApplicationBuilder,
  updateProjectConfigForApplicationBuilder,
  updateProjectConfigForBrowserBuilder,
  validateOptions,
} from './lib';
import type { Schema } from './schema';

export async function setupSsr(tree: Tree, schema: Schema) {
  assertSupportedAngularVersion(tree);
  validateOptions(tree, schema);
  const options = await normalizeOptions(tree, schema);

  if (!schema.skipPackageJson) {
    addDependencies(tree, options.isUsingApplicationBuilder);
  }
  generateSSRFiles(tree, options);

  if (options.hydration) {
    addHydration(tree, options);
  }

  if (!options.hydration) {
    setRouterInitialNavigation(tree, options);
  }

  if (options.isUsingApplicationBuilder) {
    updateProjectConfigForApplicationBuilder(tree, options);
    setServerTsConfigOptionsForApplicationBuilder(tree, options);
  } else {
    updateProjectConfigForBrowserBuilder(tree, options);
    generateTsConfigServerJsonForBrowserBuilder(tree, options);
  }

  addServerFile(tree, options);

  if (!options.skipFormat) {
    await formatFiles(tree);
  }

  return () => {
    installPackagesTask(tree);
  };
}

export default setupSsr;

import { type Tree } from '@nx/devkit';
import {
  getDeclaredPackageVersion,
  getInstalledPackageVersion,
} from '@nx/devkit/internal';
import { major } from 'semver';

export const nxVersion = require('../../package.json').version;

export const minSupportedExpressVersion = '4.0.0';

// Fresh-install constants (latest supported major).
export const expressVersion = '^5.1.0';
export const expressTypingsVersion = '^5.0.0';

type ExpressVersions = {
  expressVersion: string;
  expressTypingsVersion: string;
};

const latestVersions: ExpressVersions = {
  expressVersion,
  expressTypingsVersion,
};

type CompatVersions = 4;
const versionMap: Record<CompatVersions, ExpressVersions> = {
  4: {
    expressVersion: '^4.21.2',
    expressTypingsVersion: '^4.17.21',
  },
};

export function versions(tree: Tree): ExpressVersions {
  const installedExpressVersion = getInstalledExpressVersion(tree);
  if (!installedExpressVersion) {
    return latestVersions;
  }
  const expressMajorVersion = major(installedExpressVersion);
  return versionMap[expressMajorVersion as CompatVersions] ?? latestVersions;
}

export function getInstalledExpressVersion(tree?: Tree): string | null {
  if (!tree) {
    return getInstalledPackageVersion('express');
  }
  return getDeclaredPackageVersion(tree, 'express');
}

import { Socket } from 'net';
import { performance } from 'perf_hooks';
import { serializeResult } from '../socket-utils';
import { serverLogger } from '../logger';
import { getCachedSerializedProjectGraphPromise } from './project-graph-incremental-recomputation';
import { HandlerResult } from './server';

export async function handleRequestProjectGraph(
  socket: Socket
): Promise<HandlerResult> {
  try {
    performance.mark('server-connection');
    serverLogger.requestLog('Client Request for Project Graph Received');

    const result = await getCachedSerializedProjectGraphPromise(socket);
    if (result.error) {
      return {
        description: `Error when preparing serialized project graph.`,
        error: result.error,
      };
    }

    const serializedResult = serializeResult(
      result.error,
      result.serializedProjectGraph,
      result.serializedSourceMaps
    );
    if (!serializedResult) {
      return {
        description: `Error when serializing project graph result.`,
        error: new Error(
          'Critical error when serializing server result, check server logs'
        ),
      };
    }

    performance.mark('serialized-project-graph-ready');
    performance.measure(
      'total for creating and serializing project graph',
      'server-connection',
      'serialized-project-graph-ready'
    );

    return { response: serializedResult, description: 'project-graph' };
  } catch (e) {
    return {
      description: `Unexpected error when creating Project Graph.`,
      error: e,
    };
  }
}

